import azure.functions as func
import logging
import json
import os
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
from datetime import datetime
import hashlib

app = func.FunctionApp()

# Environment variables
STORAGE_ACCOUNT_URL = os.environ.get('STORAGE_ACCOUNT_URL')
COSMOS_ENDPOINT = os.environ.get('COSMOS_ENDPOINT')
COSMOS_DATABASE_NAME = os.environ.get('COSMOS_DATABASE_NAME', 'ProcessedFiles')
COSMOS_CONTAINER_NAME = os.environ.get('COSMOS_CONTAINER_NAME', 'FileResults')
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get('EVENT_GRID_TOPIC_ENDPOINT')

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()

def get_blob_service_client():
    if not STORAGE_ACCOUNT_URL:
        raise ValueError("STORAGE_ACCOUNT_URL environment variable is not set")
    return BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)

def get_cosmos_client():
    if not COSMOS_ENDPOINT:
        raise ValueError("COSMOS_ENDPOINT environment variable is not set")
    return CosmosClient(url=COSMOS_ENDPOINT, credential=credential)

def get_event_grid_client():
    if not EVENT_GRID_TOPIC_ENDPOINT:
        raise ValueError("EVENT_GRID_TOPIC_ENDPOINT environment variable is not set")
    return EventGridPublisherClient(EVENT_GRID_TOPIC_ENDPOINT, credential)

def sanitize_input(data):
    """Sanitize input data to prevent injection attacks"""
    if isinstance(data, str):
        # Remove potentially dangerous characters
        return data.replace('\x00', '').strip()
    elif isinstance(data, dict):
        return {sanitize_input(k): sanitize_input(v) for k, v in data.items()}
    elif isinstance(data, list):
        return [sanitize_input(item) for item in data]
    return data

def validate_blob_path(blob_path):
    """Validate blob path to prevent path traversal attacks"""
    if not blob_path:
        raise ValueError("Blob path cannot be empty")
    
    # Check for path traversal attempts
    if '..' in blob_path or blob_path.startswith('/'):
        raise ValueError("Invalid blob path detected")
    
    return blob_path

def calculate_file_hash(content):
    """Calculate SHA-256 hash of file content"""
    return hashlib.sha256(content).hexdigest()

@app.blob_trigger(arg_name="myblob", path="input-files/{name}",
                  connection="STORAGE_ACCOUNT_CONNECTION")
def process_blob_file(myblob: func.InputStream):
    """
    Process files uploaded to Blob Storage
    """
    try:
        logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
        
        # Validate blob name
        blob_name = validate_blob_path(myblob.name)
        
        # Read blob content with size limit to prevent memory exhaustion
        MAX_FILE_SIZE = 100 * 1024 * 1024  # 100 MB
        if myblob.length > MAX_FILE_SIZE:
            raise ValueError(f"File size exceeds maximum allowed size of {MAX_FILE_SIZE} bytes")
        
        content = myblob.read()
        
        # Calculate file hash for integrity verification
        file_hash = calculate_file_hash(content)
        
        # Process the file (example: count lines for text files)
        result = process_file_content(content, blob_name)
        
        # Add metadata
        result['file_hash'] = file_hash
        result['file_size'] = myblob.length
        result['blob_name'] = blob_name
        result['processed_at'] = datetime.utcnow().isoformat()
        
        # Sanitize result data
        result = sanitize_input(result)
        
        # Write to Cosmos DB
        write_to_cosmos(result)
        
        # Send notification via Event Grid
        send_event_notification(result)
        
        logging.info(f"Successfully processed blob: {blob_name}")
        
    except ValueError as ve:
        logging.error(f"Validation error: {str(ve)}")
        raise
    except Exception as e:
        logging.error(f"Error processing blob: {str(e)}")
        raise

def process_file_content(content, blob_name):
    """
    Process file content and extract relevant information
    """
    result = {
        'id': hashlib.sha256(f"{blob_name}{datetime.utcnow().isoformat()}".encode()).hexdigest(),
        'status': 'processed'
    }
    
    try:
        # Example processing: decode as text and count lines
        text_content = content.decode('utf-8', errors='ignore')
        lines = text_content.split('\n')
        
        result['line_count'] = len(lines)
        result['character_count'] = len(text_content)
        result['content_type'] = 'text'
        
        # Extract first 100 characters as preview (sanitized)
        preview = text_content[:100].replace('\x00', '').strip()
        result['preview'] = preview
        
    except Exception as e:
        logging.warning(f"Could not process as text: {str(e)}")
        result['content_type'] = 'binary'
        result['line_count'] = 0
        result['character_count'] = 0
    
    return result

def write_to_cosmos(data):
    """
    Write processed results to Cosmos DB
    """
    try:
        cosmos_client = get_cosmos_client()
        
        # Create database if it doesn't exist
        database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
        
        # Create container if it doesn't exist
        container = database.create_container_if_not_exists(
            id=COSMOS_CONTAINER_NAME,
            partition_key=PartitionKey(path="/id"),
            offer_throughput=400
        )
        
        # Validate data structure
        if 'id' not in data:
            raise ValueError("Data must contain 'id' field")
        
        # Upsert item to Cosmos DB
        container.upsert_item(body=data)
        
        logging.info(f"Successfully wrote data to Cosmos DB: {data['id']}")
        
    except Exception as e:
        logging.error(f"Error writing to Cosmos DB: {str(e)}")
        raise

def send_event_notification(data):
    """
    Send notification via Event Grid
    """
    try:
        event_grid_client = get_event_grid_client()
        
        # Create event with sanitized data
        event = EventGridEvent(
            event_type="FileProcessing.Completed",
            data={
                'id': data.get('id', ''),
                'blob_name': data.get('blob_name', ''),
                'status': data.get('status', ''),
                'processed_at': data.get('processed_at', ''),
                'file_size': data.get('file_size', 0),
                'file_hash': data.get('file_hash', '')
            },
            subject=f"file/{data.get('blob_name', 'unknown')}",
            data_version="1.0"
        )
        
        # Send event
        event_grid_client.send([event])
        
        logging.info(f"Successfully sent Event Grid notification for: {data.get('blob_name', 'unknown')}")
        
    except Exception as e:
        logging.error(f"Error sending Event Grid notification: {str(e)}")
        raise

@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """
    Health check endpoint
    """
    try:
        # Verify connectivity to services
        health_status = {
            'status': 'healthy',
            'timestamp': datetime.utcnow().isoformat(),
            'services': {}
        }
        
        # Check Blob Storage
        try:
            blob_client = get_blob_service_client()
            blob_client.get_account_information()
            health_status['services']['blob_storage'] = 'connected'
        except Exception as e:
            health_status['services']['blob_storage'] = f'error: {str(e)}'
            health_status['status'] = 'degraded'
        
        # Check Cosmos DB
        try:
            cosmos_client = get_cosmos_client()
            list(cosmos_client.list_databases())
            health_status['services']['cosmos_db'] = 'connected'
        except Exception as e:
            health_status['services']['cosmos_db'] = f'error: {str(e)}'
            health_status['status'] = 'degraded'
        
        # Check Event Grid
        try:
            if EVENT_GRID_TOPIC_ENDPOINT:
                health_status['services']['event_grid'] = 'configured'
            else:
                health_status['services']['event_grid'] = 'not configured'
        except Exception as e:
            health_status['services']['event_grid'] = f'error: {str(e)}'
        
        status_code = 200 if health_status['status'] == 'healthy' else 503
        
        return func.HttpResponse(
            json.dumps(health_status),
            status_code=status_code,
            mimetype="application/json"
        )
        
    except Exception as e:
        logging.error(f"Health check failed: {str(e)}")
        return func.HttpResponse(
            json.dumps({'status': 'unhealthy', 'error': str(e)}),
            status_code=503,
            mimetype="application/json"
        )

@app.route(route="process-manual", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def manual_process(req: func.HttpRequest) -> func.HttpResponse:
    """
    Manually trigger file processing for a specific blob
    """
    try:
        # Parse request body
        req_body = req.get_json()
        
        if not req_body or 'container_name' not in req_body or 'blob_name' not in req_body:
            return func.HttpResponse(
                json.dumps({'error': 'container_name and blob_name are required'}),
                status_code=400,
                mimetype="application/json"
            )
        
        container_name = sanitize_input(req_body['container_name'])
        blob_name = validate_blob_path(sanitize_input(req_body['blob_name']))
        
        # Get blob content
        blob_service_client = get_blob_service_client()
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        
        # Check if blob exists
        if not blob_client.exists():
            return func.HttpResponse(
                json.dumps({'error': 'Blob not found'}),
                status_code=404,
                mimetype="application/json"
            )
        
        # Download blob
        blob_data = blob_client.download_blob()
        content = blob_data.readall()
        
        # Check file size
        MAX_FILE_SIZE = 100 * 1024 * 1024
        if len(content) > MAX_FILE_SIZE:
            return func.HttpResponse(
                json.dumps({'error': f'File size exceeds maximum allowed size of {MAX_FILE_SIZE} bytes'}),
                status_code=400,
                mimetype="application/json"
            )
        
        # Calculate file hash
        file_hash = calculate_file_hash(content)
        
        # Process file
        result = process_file_content(content, blob_name)
        result['file_hash'] = file_hash
        result['file_size'] = len(content)
        result['blob_name'] = blob_name
        result['processed_at'] = datetime.utcnow().isoformat()
        result['trigger_type'] = 'manual'
        
        # Sanitize result
        result = sanitize_input(result)
        
        # Write to Cosmos DB
        write_to_cosmos(result)
        
        # Send notification
        send_event_notification(result)
        
        return func.HttpResponse(
            json.dumps({'status': 'success', 'result': result}),
            status_code=200,
            mimetype="application/json"
        )
        
    except ValueError as ve:
        return func.HttpResponse(
            json.dumps({'error': str(ve)}),
            status_code=400,
            mimetype="application/json"
        )
    except Exception as e:
        logging.error(f"Error in manual processing: {str(e)}")
        return func.HttpResponse(
            json.dumps({'error': 'Internal server error'}),
            status_code=500,
            mimetype="application/json"
        )